mapper.select:
select statistics.id id, grid_city.city_id cityCode, statistics.aqi_id aqiValue, concat(statistics.confirm_date, ' ', statistics.confirm_time) confirmTime, statistics.gm_id gmId, (case when statistics.aqi_id >= 3 then 1 else 0 end) isExceed from statistics left join grid_city on grid_city.city_id = statistics.city_id
and grid_city.city_name like concat('%', #{queryVo.cityName}, '%')
and (case when statistics.aqi_id >= 3 then 1 else 0 end) = #{queryVo.isExceed}
and concat(statistics.confirm_date, ' ', statistics.confirm_time) >= #{queryVo.startTime}
and concat(statistics.confirm_date, ' ', statistics.confirm_time) <= #{queryVo.endTime}
